def get_position(start_position, time):
    if time % 2 == 0:
        if start_position == '^':
            return 'v'
        elif start_position == 'v':
            return '^'
        elif start_position == '<':
            return '>'
        elif start_position == '>':
            return '<'
    else:
        if start_position == '^':
            return '>'
        elif start_position == 'v':
            return '<'
        elif start_position == '<':
            return 'v'
        elif start_position == '>':
            return '^'


def get_direction(start_position, end_position):
    if start_position == end_position:
        return 'undefined'
    elif start_position == '^':
        if end_position == 'v':
            return 'ccw'
        else:
            return 'cw'
    elif start_position == 'v':
        if end_position == '^':
            return 'ccw'
        else:
            return 'cw'
    elif start_position == '<':
        if end_position == '>':
            return 'ccw'
        else:
            return 'cw'
    elif start_position == '>':
        if end_position == '<':
            return 'ccw'
        else:
            return 'cw'


start_position, end_position = input().split()
time = int(input())

end_position = get_position(start_position, time)
direction = get_direction(start_position, end_position)

print(direction)
